{
  "name": "PhysiCore AI: Multiphysics Robotics Simulator",
  "description": "A high-fidelity physics simulation engine and robot training platform inspired by massive multiphysics datasets like The Well and PhysGaia. Features real-time rigid body dynamics, fluid particles, and textile constraints powered by Gemini for intelligent robot control.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum SimMode {
  RIGID_BODY = 'RIGID_BODY',
  FLUID_DYNAMICS = 'FLUID_DYNAMICS',
  SOFT_BODY = 'SOFT_BODY',
  ACOUSTICS = 'ACOUSTICS'
}

export interface SimState {
  time: number;
  entities: number;
  avgVelocity: number;
  stability: number;
  collisions: number;
}

export interface TelemetryPoint {
  time: number;
  value: number;
  label: string;
}

export interface RobotBrainResponse {
  analysis: string;
  optimizationPlan: string[];
  suggestedAction: string;
  parameters: {
    gravity: number;
    friction: number;
    learningRate: number;
  };
}

import { GoogleGenAI, Type } from "@google/genai";
import { SimState, SimMode, RobotBrainResponse } from "../types";

export const analyzeSimulation = async (
  state: SimState,
  mode: SimMode,
  customPrompt: string = ""
): Promise<RobotBrainResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    System: You are the core "PhysiCore Brain", a world-class physics engine reasoning unit.
    Dataset context: Trained on 15TB of multiphysics (The Well, PhysGaia, SimBenchmark, AhmedML).

    Current Simulation Mode: ${mode}
    State Metrics:
    - Time elapsed: ${state.time}s
    - Entity count: ${state.entities}
    - Avg Velocity: ${state.avgVelocity} m/s
    - World Stability: ${state.stability}%
    - Recent Collisions: ${state.collisions}

    User Query/Instruction: ${customPrompt || "Perform real-time optimization of robot kinematics based on current simulation dynamics."}

    Task: Provide a high-level scientific analysis and suggested next steps for training optimization.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          analysis: { type: Type.STRING },
          optimizationPlan: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          suggestedAction: { type: Type.STRING },
          parameters: {
            type: Type.OBJECT,
            properties: {
              gravity: { type: Type.NUMBER },
              friction: { type: Type.NUMBER },
              learningRate: { type: Type.NUMBER }
            }
          }
        },
        required: ["analysis", "optimizationPlan", "suggestedAction", "parameters"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim()) as RobotBrainResponse;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid brain response format");
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { SimMode, SimState } from '../types';

declare const Matter: any;

interface SimulationCanvasProps {
  mode: SimMode;
  onStateUpdate: (state: SimState) => void;
  isRunning: boolean;
  gravity: number;
}

const SimulationCanvas: React.FC<SimulationCanvasProps> = ({ mode, onStateUpdate, isRunning, gravity }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<any>(null);
  const renderRef = useRef<any>(null);
  const [entities, setEntities] = useState(0);

  useEffect(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const engine = Matter.Engine.create();
    engineRef.current = engine;
    engine.world.gravity.y = gravity;

    const render = Matter.Render.create({
      element: containerRef.current,
      canvas: canvasRef.current,
      engine: engine,
      options: {
        width: containerRef.current.clientWidth,
        height: containerRef.current.clientHeight,
        wireframes: false,
        background: 'transparent',
        pixelRatio: window.devicePixelRatio,
      }
    });
    renderRef.current = render;

    // Create boundaries
    const { width, height } = containerRef.current;
    const ground = Matter.Bodies.rectangle(width / 2, height + 25, width, 50, { isStatic: true, render: { fillStyle: '#1e293b' } });
    const wallLeft = Matter.Bodies.rectangle(-25, height / 2, 50, height, { isStatic: true });
    const wallRight = Matter.Bodies.rectangle(width + 25, height / 2, 50, height, { isStatic: true });
    const ceiling = Matter.Bodies.rectangle(width / 2, -25, width, 50, { isStatic: true });

    Matter.Composite.add(engine.world, [ground, wallLeft, wallRight, ceiling]);

    // Initial objects
    const createEntities = () => {
      if (mode === SimMode.RIGID_BODY) {
        const stack = Matter.Composites.stack(width / 4, 100, 8, 4, 0, 0, (x: number, y: number) => {
          return Matter.Bodies.rectangle(x, y, 40, 40, {
            render: {
              fillStyle: Math.random() > 0.5 ? '#0ea5e9' : '#f43f5e',
              strokeStyle: '#f8fafc',
              lineWidth: 1
            }
          });
        });
        Matter.Composite.add(engine.world, [stack]);
      } else if (mode === SimMode.FLUID_DYNAMICS || mode === SimMode.ACOUSTICS) {
         // Particle simulation approximation
         const particles = [];
         for(let i=0; i<150; i++) {
           particles.push(Matter.Bodies.circle(Math.random() * width, Math.random() * 200, 5, {
             friction: 0.001,
             restitution: 0.8,
             render: { fillStyle: '#38bdf8' }
           }));
         }
         Matter.Composite.add(engine.world, particles);
      } else if (mode === SimMode.SOFT_BODY) {
        const cloth = Matter.Composites.softBody(width / 3, 100, 10, 10, 0, 0, true, 8, {
           render: { fillStyle: '#d946ef', strokeStyle: '#f8fafc' },
           collisionFilter: { group: Matter.Body.nextGroup(true) }
        });
        Matter.Composite.add(engine.world, [cloth]);
      }
    };

    createEntities();

    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);
    Matter.Render.run(render);

    const updateInterval = setInterval(() => {
      const allBodies = Matter.Composite.allBodies(engine.world);
      const movingBodies = allBodies.filter((b: any) => !b.isStatic);
      const avgVel = movingBodies.length > 0 
        ? movingBodies.reduce((acc: number, b: any) => acc + (Math.abs(b.velocity.x) + Math.abs(b.velocity.y)), 0) / movingBodies.length
        : 0;

      onStateUpdate({
        time: Math.round(engine.timing.timestamp / 1000),
        entities: allBodies.length,
        avgVelocity: avgVel,
        stability: Math.max(0, 100 - (avgVel * 10)),
        collisions: 0 // Simplification
      });
      setEntities(allBodies.length);
    }, 1000);

    return () => {
      Matter.Engine.clear(engine);
      Matter.Render.stop(render);
      clearInterval(updateInterval);
      if (render.canvas) render.canvas.remove();
    };
  }, [mode]);

  useEffect(() => {
    if (engineRef.current) {
      engineRef.current.world.gravity.y = gravity;
    }
  }, [gravity]);

  return (
    <div ref={containerRef} className="w-full h-full relative overflow-hidden bg-slate-900 rounded-xl border border-slate-800 shadow-2xl">
      <canvas ref={canvasRef} className="block w-full h-full" />
      <div className="absolute top-4 left-4 flex gap-2">
        <div className="bg-black/60 backdrop-blur-md px-3 py-1 rounded border border-white/10 text-[10px] uppercase tracking-widest text-blue-400 font-bold">
          Live Rendering
        </div>
        <div className="bg-black/60 backdrop-blur-md px-3 py-1 rounded border border-white/10 text-[10px] uppercase tracking-widest text-emerald-400 font-bold">
          {entities} Entities Active
        </div>
      </div>
    </div>
  );
};

export default SimulationCanvas;

