};

export default App;

export enum SimMode {
  MPC_STABILIZATION = 'MPC_STABILIZATION',
  TRAJECTORY_FOLLOWING = 'TRAJECTORY_FOLLOWING',
  ADAPTIVE_GRASPING = 'ADAPTIVE_GRASPING',
  FLUID_INTERACTION = 'FLUID_INTERACTION'
}

export interface StateVector {
  position: { x: number; y: number };
  velocity: { x: number; y: number };
  angle: number;
  angularVelocity: number;
}

export interface PredictionPoint extends StateVector {
  timestamp: number;
  uncertainty: number;
}

export interface ControlAction {
  force: { x: number; y: number };
  torque: number;
}

export interface SimState {
  current: StateVector;
  target: StateVector;
  predictionError: number;
  controlEffort: number;
  stability: number;
  time: number;
}

export interface TelemetryPoint {
  time: number;
  value: number;
  label: string;
}

export interface WorldModelResponse {
  systemIdentification: {
    estimatedMass: number;
    estimatedFriction: number;
    estimatedElasticity: number;
    uncertaintyScore: number;
  };
  controlLaw: string; // Symbolic or descriptive control strategy
  jacobianApproximation: number[][];
  optimizationPlan: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { SimState, SimMode, WorldModelResponse } from "../types";

export const adaptWorldModel = async (
  state: SimState,
  mode: SimMode,
  history: any[]
): Promise<WorldModelResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    System: You are the "Predictive Dynamics Engine" for a differentiable robot simulator.
    Role: Perform System Identification and Jacobian Approximation.

    Context:
    - Mode: ${mode}
    - State: Pos(${state.current.position.x}, ${state.current.position.y}), Vel(${state.current.velocity.x}, ${state.current.velocity.y})
    - Target: Pos(${state.target.position.x}, ${state.target.position.y})
    - Prediction Error: ${state.predictionError}
    - Recent History (last 5 frames): ${JSON.stringify(history.slice(-5))}

    Task:
    1. Estimate physical parameters from observed dynamics (system ID).
    2. Provide a control law for Model Predictive Control (MPC).
    3. Generate a 2x2 Jacobian matrix for velocity control.

    Format: Return strict JSON.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          systemIdentification: {
            type: Type.OBJECT,
            properties: {
              estimatedMass: { type: Type.NUMBER },
              estimatedFriction: { type: Type.NUMBER },
              estimatedElasticity: { type: Type.NUMBER },
              uncertaintyScore: { type: Type.NUMBER }
            }
          },
          controlLaw: { type: Type.STRING },
          jacobianApproximation: {
            type: Type.ARRAY,
            items: {
              type: Type.ARRAY,
              items: { type: Type.NUMBER }
            }
          },
          optimizationPlan: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["systemIdentification", "controlLaw", "jacobianApproximation", "optimizationPlan"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim()) as WorldModelResponse;
  } catch (e) {
    console.error("Neural adapter failed", e);
    throw new Error("Invalid brain response format");
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { SimMode, SimState, StateVector, PredictionPoint } from '../types';

declare const Matter: any;

interface SimulationCanvasProps {
  mode: SimMode;
  onStateUpdate: (state: SimState) => void;
  target: { x: number; y: number };
  physicsParams: { gravity: number; friction: number };
}

const SimulationCanvas: React.FC<SimulationCanvasProps> = ({ mode, onStateUpdate, target, physicsParams }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<any>(null);
  const robotRef = useRef<any>(null);
  const targetRef = useRef(target);
  const predictionsRef = useRef<PredictionPoint[]>([]);

  useEffect(() => { targetRef.current = target; }, [target]);

  useEffect(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const engine = Matter.Engine.create();
    engineRef.current = engine;
    engine.world.gravity.y = physicsParams.gravity;

    const render = Matter.Render.create({
      element: containerRef.current,
      canvas: canvasRef.current,
      engine: engine,
      options: {
        width: containerRef.current.clientWidth,
        height: containerRef.current.clientHeight,
        wireframes: false,
        background: 'transparent',
      }
    });

    const { width, height } = containerRef.current;

    // Controlled Robot Entity
    const robot = Matter.Bodies.rectangle(width / 2, height / 2, 60, 30, {
      friction: physicsParams.friction,
      restitution: 0.5,
      render: { fillStyle: '#3b82f6', strokeStyle: '#fff', lineWidth: 2 }
    });
    robotRef.current = robot;

    const ground = Matter.Bodies.rectangle(width / 2, height + 25, width, 50, { isStatic: true, render: { fillStyle: '#0f172a' } });
    Matter.Composite.add(engine.world, [robot, ground]);

    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);
    Matter.Render.run(render);

    // Predictive Control Loop (100Hz)
    const controlLoop = setInterval(() => {
      const b = robotRef.current;
      const t = targetRef.current;

      // Simple P-Controller for demonstration (The "Real" controller is adapted by Gemini)
      const dx = t.x - b.position.x;
      const dy = t.y - b.position.y;

      const forceMultiplier = 0.0005;
      Matter.Body.applyForce(b, b.position, { 
        x: dx * forceMultiplier - b.velocity.x * 0.001, 
        y: dy * forceMultiplier - b.velocity.y * 0.001 
      });

      // Update State
      onStateUpdate({
        current: {
          position: { x: b.position.x, y: b.position.y },
          velocity: { x: b.velocity.x, y: b.velocity.y },
          angle: b.angle,
          angularVelocity: b.angularVelocity
        },
        target: {
          position: { x: t.x, y: t.y },
          velocity: { x: 0, y: 0 },
          angle: 0,
          angularVelocity: 0
        },
        predictionError: Math.sqrt(dx*dx + dy*dy),
        controlEffort: Math.abs(dx) + Math.abs(dy),
        stability: 100 - Math.min(100, (Math.abs(b.angularVelocity) * 100)),
        time: Date.now()
      });

      // Project Predicted Trajectory
      const futurePoints: PredictionPoint[] = [];
      let px = b.position.x, py = b.position.y, vx = b.velocity.x, vy = b.velocity.y;
      for(let i=1; i<=20; i++) {
        vx += (t.x - px) * forceMultiplier * 0.5;
        vy += (t.y - py) * forceMultiplier * 0.5 + (physicsParams.gravity * 0.1);
        px += vx;
        py += vy;
        futurePoints.push({
          timestamp: Date.now() + i * 16,
          position: { x: px, y: py },
          velocity: { x: vx, y: vy },
          angle: 0,
          angularVelocity: 0,
          uncertainty: i * 0.05
        });
      }
      predictionsRef.current = futurePoints;
    }, 16);

    // Custom Overlay Drawing for Trajectories
    const drawOverlay = () => {
      const ctx = canvasRef.current?.getContext('2d');
      if (!ctx) return;

      // Draw Predictions
      ctx.beginPath();
      ctx.setLineDash([5, 5]);
      ctx.strokeStyle = 'rgba(56, 189, 248, 0.5)';
      predictionsRef.current.forEach((p, idx) => {
        if (idx === 0) ctx.moveTo(p.position.x, p.position.y);
        else ctx.lineTo(p.position.x, p.position.y);
      });
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw Target
      ctx.beginPath();
      ctx.arc(targetRef.current.x, targetRef.current.y, 10, 0, Math.PI * 2);
      ctx.strokeStyle = '#f43f5e';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.fillStyle = 'rgba(244, 63, 94, 0.2)';
      ctx.fill();

      requestAnimationFrame(drawOverlay);
    };
    drawOverlay();

    return () => {
      clearInterval(controlLoop);
      Matter.Engine.clear(engine);
      Matter.Render.stop(render);
    };
  }, [mode]);

  useEffect(() => {
    if (engineRef.current) engineRef.current.world.gravity.y = physicsParams.gravity;
  }, [physicsParams.gravity]);

  return (
    <div ref={containerRef} className="w-full h-full relative overflow-hidden bg-slate-950 border border-slate-800 shadow-inner">
      <canvas ref={canvasRef} className="block w-full h-full" />
      <div className="absolute bottom-4 left-4 font-mono text-[9px] text-slate-500 uppercase tracking-widest bg-black/40 p-2 rounded border border-white/5">
        Neural World Model: Active <br/>
        Differentiable Solver: 100Hz
      </div>
    </div>
  );
};

export default SimulationCanvas;

