import { StateVector, ControlInput, PhysicalParams } from "../types";

const DT = 1/60; // Simulation timestep

/**
 * Predict next state based on deterministic Lagrangian dynamics
 * x_t+1 = f(x_t, u_t; theta)
 */
export const stepDynamics = (
  x: StateVector,
  u: ControlInput,
  p: PhysicalParams
): StateVector => {
  const [px, py, vx, vy, theta, omega] = x;
  const [fx, fy] = u;

  // Accel = (Force / Mass) - Friction * Velocity + Gravity
  const ax = (fx / p.mass) - (p.friction * vx);
  const ay = (fy / p.mass) - (p.friction * vy) + p.gravity;

  const nvx = vx + ax * DT;
  const nvy = vy + ay * DT;
  const npx = px + nvx * DT;
  const npy = py + nvy * DT;

  // Simple rotation approximation (if needed for robot orientation)
  const nomega = omega; 
  const ntheta = theta + nomega * DT;

  return [npx, npy, nvx, nvy, ntheta, nomega];
};

/**
 * Numerical Jacobian computation via finite differences
 * J = df/du
 */
export const computeJacobian = (
  x: StateVector,
  u: ControlInput,
  p: PhysicalParams
): number[][] => {
  const eps = 1e-4;
  const jacobian: number[][] = [];

  for (let i = 0; i < u.length; i++) {
    const uStep = [...u] as ControlInput;
    uStep[i] += eps;
    const xPlus = stepDynamics(x, uStep, p);

    uStep[i] = u[i] - eps;
    const xMinus = stepDynamics(x, uStep, p);

    const col = xPlus.map((v, idx) => (v - xMinus[idx]) / (2 * eps));
    jacobian.push(col);
  }

  return jacobian; // 2x6 matrix
};

import { StateVector, ControlInput, PhysicalParams } from "../types";
import { stepDynamics } from "./physicsLogic";

const HORIZON = 15;
const SAMPLES = 40;
const ELITES = 8;
const ITERATIONS = 2;

/**
 * Model Predictive Control (MPC) via Sampling-based Optimization (CEM)
 */
export const computeMPCAction = (
  x0: StateVector,
  target: [number, number],
  p: PhysicalParams,
  weights: { q: number; r: number } = { q: 1.0, r: 0.1 }
): ControlInput => {
  let meanAction: ControlInput = [0, 0];
  let stdAction: ControlInput = [0.1, 0.1];

  // CEM Optimization Loop
  for (let iter = 0; iter < ITERATIONS; iter++) {
    const trajectories: { cost: number; action: ControlInput }[] = [];

    for (let s = 0; s < SAMPLES; s++) {
      // Sample initial action
      const a0: ControlInput = [
        meanAction[0] + (Math.random() - 0.5) * 2 * stdAction[0],
        meanAction[1] + (Math.random() - 0.5) * 2 * stdAction[1]
      ];

      // Roll out trajectory
      let cost = 0;
      let xt = [...x0] as StateVector;

      for (let t = 0; t < HORIZON; t++) {
        // Use a simple constant action sequence for this rollout
        xt = stepDynamics(xt, a0, p);

        // Cost = Distance Error + Control Effort
        const distSq = Math.pow(xt[0] - target[0], 2) + Math.pow(xt[1] - target[1], 2);
        const effort = Math.pow(a0[0], 2) + Math.pow(a0[1], 2);

        cost += distSq * weights.q + effort * weights.r;
      }

      trajectories.push({ cost, action: a0 });
    }

    // Sort by cost and pick elites
    trajectories.sort((a, b) => a.cost - b.cost);
    const elites = trajectories.slice(0, ELITES);

    // Update mean and std from elites
    const newMean: ControlInput = [
      elites.reduce((sum, e) => sum + e.action[0], 0) / ELITES,
      elites.reduce((sum, e) => sum + e.action[1], 0) / ELITES
    ];

    const newStd: ControlInput = [
      Math.sqrt(elites.reduce((sum, e) => sum + Math.pow(e.action[0] - newMean[0], 2), 0) / ELITES) + 0.01,
      Math.sqrt(elites.reduce((sum, e) => sum + Math.pow(e.action[1] - newMean[1], 2), 0) / ELITES) + 0.01
    ];

    meanAction = newMean;
    stdAction = newStd;
  }

  return meanAction;
};

import { StateVector, ControlInput, PhysicalParams } from "../types";

const LEARNING_RATE = 0.005;
const DT = 1/60;

/**
 * Update physical parameter estimates based on observed state transitions
 */
export const updateSystemID = (
  prevX: StateVector,
  action: ControlInput,
  currX: StateVector,
  params: PhysicalParams
): PhysicalParams => {
  const [px, py, vx, vy] = prevX;
  const [fx, fy] = action;
  const [cpx, cpy, cvx, cvy] = currX;

  // Observed Accelerations
  const ax_obs = (cvx - vx) / DT;
  const ay_obs = (cvy - vy) / DT;

  // Predicted Accelerations using current estimates
  const ax_pred = (fx / params.mass) - (params.friction * vx);
  const ay_pred = (fy / params.mass) - (params.friction * vy) + params.gravity;

  // Gradients for Mass (m)
  // dError/dm = -Fx/m^2
  const dError_dm_x = (ax_pred - ax_obs) * (-fx / Math.pow(params.mass, 2));
  const dError_dm_y = (ay_pred - ay_obs) * (-fy / Math.pow(params.mass, 2));

  // Gradients for Friction (f)
  // dError/df = -v
  const dError_df_x = (ax_pred - ax_obs) * (-vx);
  const dError_df_y = (ay_pred - ay_obs) * (-vy);

  // Update estimates
  const newMass = Math.max(0.1, params.mass - LEARNING_RATE * (dError_dm_x + dError_dm_y));
  const newFriction = Math.max(0, params.friction - LEARNING_RATE * (dError_df_x + dError_df_y));

  return {
    ...params,
    mass: newMass,
    friction: newFriction
  };
};

import { StateVector, ControlInput } from "../types";

/**
 * Extremely lightweight Linear Regression dynamics model
 * Acts as a placeholder for a learned neural world model.
 */
export class LearnedWorldModel {
  // Weights for a simple linear transformation
  private weights: number[][] = Array(6).fill(0).map(() => Array(8).fill(0).map(() => Math.random() * 0.01));

  /**
   * Predict next state: x_hat = G * [state, action]
   */
  public predict(x: StateVector, u: ControlInput): StateVector {
    const input = [...x, ...u];
    const output = this.weights.map(row => 
      row.reduce((sum, w, i) => sum + w * input[i], 0)
    );
    // Residual correction logic could go here
    return output as StateVector;
  }

  /**
   * Online training step
   */
  public train(x: StateVector, u: ControlInput, xNext: StateVector) {
    const input = [...x, ...u];
    const lr = 0.001;

    for (let i = 0; i < 6; i++) {
      const pred = this.weights[i].reduce((sum, w, j) => sum + w * input[j], 0);
      const error = xNext[i] - pred;

      for (let j = 0; j < 8; j++) {
        this.weights[i][j] += lr * error * input[j];
      }
    }
  }
}

export const neuralWorldModel = new LearnedWorldModel();

import { GoogleGenAI, Type } from "@google/genai";
import { SimState, MetaAnalysisResponse } from "../types";

export const performMetaAnalysis = async (
  state: SimState,
  history: SimState[]
): Promise<MetaAnalysisResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    System: You are the "PhysiCore Meta-Analyst".
    Role: Interpret telemetry and diagnostics from a model-based predictive control (MPC) system.

    Diagnostics:
    - Target: [${state.target[0]}, ${state.target[1]}]
    - Estimated Mass: ${state.estimatedParams.mass.toFixed(3)}
    - Estimated Friction: ${state.estimatedParams.friction.toFixed(3)}
    - Prediction L2 Loss: ${state.predictionError.toFixed(5)}
    - Control Effort: ${state.controlEffort.toFixed(3)}
    - Mode: ${state.stability > 80 ? 'Stable Convergence' : 'Oscillatory/Unstable'}

    Analyze the trajectory history and parameter drift. Identify if the model is over-damped or if the system ID is diverging.

    Return strict JSON with specific suggested Q/R weights for the MPC cost function.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          insight: { type: Type.STRING },
          diagnostics: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          suggestedCostTweaks: {
            type: Type.OBJECT,
            properties: {
              q_weight: { type: Type.NUMBER },
              r_weight: { type: Type.NUMBER }
            }
          }
        },
        required: ["insight", "diagnostics", "suggestedCostTweaks"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim()) as MetaAnalysisResponse;
  } catch (e) {
    console.error("Meta-analyst uplink failed", e);
    throw new Error("Invalid analysis response format");
  }
};

import React, { useEffect, useRef } from 'react';
import { SimMode, SimState, StateVector, ControlInput } from '../types';
import { stepDynamics } from '../services/physicsLogic';

declare const Matter: any;

interface SimulationCanvasProps {
  mode: SimMode;
  onStateUpdate: (state: SimState) => void;
  target: [number, number];
  controlAction: ControlInput;
  physicsPriors: { mass: number; friction: number; gravity: number };
}

const SimulationCanvas: React.FC<SimulationCanvasProps> = ({ mode, onStateUpdate, target, controlAction, physicsPriors }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<any>(null);
  const robotRef = useRef<any>(null);

  useEffect(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const engine = Matter.Engine.create();
    engineRef.current = engine;
    engine.world.gravity.y = 0; // Handled manually in dynamics

    const render = Matter.Render.create({
      element: containerRef.current,
      canvas: canvasRef.current,
      engine: engine,
      options: {
        width: containerRef.current.clientWidth,
        height: containerRef.current.clientHeight,
        wireframes: false,
        background: 'transparent',
      }
    });

    const { width, height } = containerRef.current;

    const robot = Matter.Bodies.rectangle(width / 2, height / 2, 60, 30, {
      friction: 0,
      airFriction: 0,
      restitution: 0.1,
      render: { fillStyle: '#3b82f6', strokeStyle: '#fff', lineWidth: 2 }
    });
    robotRef.current = robot;

    const ground = Matter.Bodies.rectangle(width / 2, height + 25, width, 50, { isStatic: true, render: { fillStyle: '#0f172a' } });
    Matter.Composite.add(engine.world, [robot, ground]);

    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);
    Matter.Render.run(render);

    const controlLoop = setInterval(() => {
      const b = robotRef.current;

      // Apply Force from MPC Controller
      Matter.Body.applyForce(b, b.position, { 
        x: controlAction[0] * 0.001, 
        y: (controlAction[1] + physicsPriors.gravity * 10) * 0.001 
      });

      // Update Parent State
      onStateUpdate({
        current: [b.position.x, b.position.y, b.velocity.x, b.velocity.y, b.angle, b.angularVelocity],
        target: target,
        estimatedParams: physicsPriors,
        predictionError: 0, // Calculated in App
        controlEffort: Math.abs(controlAction[0]) + Math.abs(controlAction[1]),
        stability: 100 - Math.min(100, (Math.abs(b.angularVelocity) * 100)),
        time: Date.now(),
        controlAction: controlAction
      });
    }, 16);

    const drawOverlay = () => {
      const ctx = canvasRef.current?.getContext('2d');
      if (!ctx || !robotRef.current) return;

      // Draw Projected Rollout (Ground Truth Visualization)
      let tempX: StateVector = [
        robotRef.current.position.x,
        robotRef.current.position.y,
        robotRef.current.velocity.x,
        robotRef.current.velocity.y,
        robotRef.current.angle,
        robotRef.current.angularVelocity
      ];

      ctx.beginPath();
      ctx.setLineDash([2, 4]);
      ctx.strokeStyle = 'rgba(56, 189, 248, 0.4)';
      ctx.moveTo(tempX[0], tempX[1]);

      for (let i = 0; i < 20; i++) {
        tempX = stepDynamics(tempX, controlAction, physicsPriors);
        ctx.lineTo(tempX[0], tempX[1]);
      }
      ctx.stroke();
      ctx.setLineDash([]);

      // Draw Target
      ctx.beginPath();
      ctx.arc(target[0], target[1], 8, 0, Math.PI * 2);
      ctx.strokeStyle = '#f43f5e';
      ctx.stroke();

      requestAnimationFrame(drawOverlay);
    };
    drawOverlay();

    return () => {
      clearInterval(controlLoop);
      Matter.Engine.clear(engine);
      Matter.Render.stop(render);
    };
  }, [mode]);

  return (
    <div ref={containerRef} className="w-full h-full relative overflow-hidden bg-slate-950 border border-slate-800">
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

export default SimulationCanvas;

