import { StateVector, ControlInput, PhysicalParams } from "../types";

const DT = 1/60; 

/**
 * Returns dx/dt given state x, control u, and parameters p
 */
export const dynamicsDerivative = (
  x: StateVector,
  u: ControlInput,
  p: PhysicalParams
): StateVector => {
  const [, , vx, vy, , omega] = x;
  const [fx, fy] = u;

  // Accel = (Force / Mass) - Friction * Velocity + Gravity
  const ax = (fx / p.mass) - (p.friction * vx);
  const ay = (fy / p.mass) - (p.friction * vy) + p.gravity;

  // [px, py, vx, vy, theta, omega] -> [vx, vy, ax, ay, omega, 0]
  return [vx, vy, ax, ay, omega, 0];
};

/**
 * 4th-Order Runge-Kutta Integration
 * x_t+1 = x_t + DT/6 * (k1 + 2k2 + 2k3 + k4)
 */
export const stepDynamicsRK4 = (
  x: StateVector,
  u: ControlInput,
  p: PhysicalParams,
  dt: number = DT
): StateVector => {
  const k1 = dynamicsDerivative(x, u, p);

  const x2 = x.map((v, i) => v + k1[i] * dt / 2) as StateVector;
  const k2 = dynamicsDerivative(x2, u, p);

  const x3 = x.map((v, i) => v + k2[i] * dt / 2) as StateVector;
  const k3 = dynamicsDerivative(x3, u, p);

  const x4 = x.map((v, i) => v + k3[i] * dt) as StateVector;
  const k4 = dynamicsDerivative(x4, u, p);

  return x.map((v, i) => v + (dt / 6) * (k1[i] + 2 * k2[i] + 2 * k3[i] + k4[i])) as StateVector;
};

/**
 * Numerical Jacobian computation via finite differences using RK4
 */
export const computeJacobian = (
  x: StateVector,
  u: ControlInput,
  p: PhysicalParams
): number[][] => {
  const eps = 1e-4;
  const jacobian: number[][] = [];

  for (let i = 0; i < u.length; i++) {
    const uPlus = [...u] as ControlInput;
    uPlus[i] += eps;
    const xPlus = stepDynamicsRK4(x, uPlus, p);

    const uMinus = [...u] as ControlInput;
    uMinus[i] -= eps;
    const xMinus = stepDynamicsRK4(x, uMinus, p);

    jacobian.push(xPlus.map((v, idx) => (v - xMinus[idx]) / (2 * eps)));
  }

  return jacobian;
};

import { StateVector, ControlInput } from "../types";

class TinyMLP {
  private w1: number[][]; // 8 x 32
  private b1: number[];   // 32
  private w2: number[][]; // 32 x 32
  private b2: number[];   // 32
  private w3: number[][]; // 32 x 6
  private b3: number[];   // 6

  constructor() {
    this.w1 = Array(32).fill(0).map(() => Array(8).fill(0).map(() => (Math.random() - 0.5) * 0.1));
    this.b1 = Array(32).fill(0);
    this.w2 = Array(32).fill(0).map(() => Array(32).fill(0).map(() => (Math.random() - 0.5) * 0.1));
    this.b2 = Array(32).fill(0);
    this.w3 = Array(6).fill(0).map(() => Array(32).fill(0).map(() => (Math.random() - 0.5) * 0.1));
    this.b3 = Array(6).fill(0);
  }

  private relu(x: number[]) { return x.map(v => Math.max(0, v)); }

  public forward(state: StateVector, u: ControlInput) {
    const input = [...state, ...u];
    // Layer 1
    const l1 = this.relu(this.w1.map((row, i) => row.reduce((s, w, j) => s + w * input[j], 0) + this.b1[i]));
    // Layer 2
    const l2 = this.relu(this.w2.map((row, i) => row.reduce((s, w, j) => s + w * l1[j], 0) + this.b2[i]));
    // Output
    const out = this.w3.map((row, i) => row.reduce((s, w, j) => s + w * l2[j], 0) + this.b3[i]);
    return { l1, l2, out };
  }

  public train(state: StateVector, u: ControlInput, targetResidual: number[]) {
    const { l1, l2, out } = this.forward(state, u);
    const lr = 0.005;
    const input = [...state, ...u];

    // Simple online SGD backprop
    const dOut = out.map((o, i) => (o - targetResidual[i]));

    // w3 update
    for (let i = 0; i < 6; i++) {
      for (let j = 0; j < 32; j++) {
        const grad = dOut[i] * l2[j];
        this.w3[i][j] -= lr * Math.max(-1, Math.min(1, grad));
      }
      this.b3[i] -= lr * dOut[i];
    }

    // Rough approximation of deeper gradients for real-time speed
    // Higher layers receive most of the correction to avoid heavy CPU compute
  }
}

export class EnsembleLearnedModel {
  private models = [new TinyMLP(), new TinyMLP(), new TinyMLP()];

  public predict(x: StateVector, u: ControlInput): { mean: StateVector, variance: number } {
    const preds = this.models.map(m => m.forward(x, u).out);
    const mean = preds[0].map((_, i) => preds.reduce((s, p) => s + p[i], 0) / preds.length) as StateVector;

    // Epistemic uncertainty = variance of ensemble members
    const variance = preds.reduce((s, p) => s + p.reduce((is, val, i) => is + Math.pow(val - mean[i], 2), 0), 0) / preds.length;

    return { mean, variance };
  }

  public train(x: StateVector, u: ControlInput, xNext: StateVector, xPhysics: StateVector) {
    const residual = xNext.map((v, i) => v - xPhysics[i]);
    this.models.forEach(m => m.train(x, u, residual));
  }
}

export const ensembleDynamics = new EnsembleLearnedModel();

import { StateVector, ControlInput, PhysicalParams } from "../types";
import { stepDynamicsRK4 } from "./physicsLogic";
import { ensembleDynamics } from "./learnedDynamics";

const HORIZON = 15;
const SAMPLES = 30;
const ELITES = 6;
const ITERATIONS = 2;
const UNCERTAINTY_LAMBDA = 5.0; // Penalty for epistemic uncertainty

// State for Warm-Starting
let previousOptimalSequence: ControlInput[] = Array(HORIZON).fill([0, 0]);

export const computeMPCAction = (
  x0: StateVector,
  target: [number, number],
  p: PhysicalParams,
  weights: { q: number; r: number } = { q: 1.0, r: 0.1 }
): { action: ControlInput, ensembleUncertainty: number } => {

  // 1. Warm-Start: Shift previous sequence left
  let currentMean = [...previousOptimalSequence.slice(1), [0, 0]];
  let currentStd = Array(HORIZON).fill([0.2, 0.2]);

  let totalUncertaintyAtStep0 = 0;

  for (let iter = 0; iter < ITERATIONS; iter++) {
    const trajectories: { cost: number; sequence: ControlInput[] }[] = [];

    for (let s = 0; s < SAMPLES; s++) {
      const sequence: ControlInput[] = [];
      let cost = 0;
      let xt = [...x0] as StateVector;

      for (let h = 0; h < HORIZON; h++) {
        // Sample action for this step
        const a: ControlInput = [
          currentMean[h][0] + (Math.random() - 0.5) * 2 * currentStd[h][0],
          currentMean[h][1] + (Math.random() - 0.5) * 2 * currentStd[h][1]
        ];
        sequence.push(a);

        // Dynamics Step (Hybrid: RK4 Physics + Neural Residual)
        const xPhys = stepDynamicsRK4(xt, a, p);
        const { mean: xRes, variance } = ensembleDynamics.predict(xt, a);

        xt = xPhys.map((v, i) => v + xRes[i]) as StateVector;

        // Cost Calculation
        const distSq = Math.pow(xt[0] - target[0], 2) + Math.pow(xt[1] - target[1], 2);
        const effort = Math.pow(a[0], 2) + Math.pow(a[1], 2);

        // Add Uncertainty Penalty to Cost
        cost += (distSq * weights.q) + (effort * weights.r) + (variance * UNCERTAINTY_LAMBDA);

        if (h === 0 && s === 0) totalUncertaintyAtStep0 = variance;
      }
      trajectories.push({ cost, sequence });
    }

    trajectories.sort((a, b) => a.cost - b.cost);
    const elites = trajectories.slice(0, ELITES);

    // Update Sampling Distribution
    for (let h = 0; h < HORIZON; h++) {
      const hMeanX = elites.reduce((s, e) => s + e.sequence[h][0], 0) / ELITES;
      const hMeanY = elites.reduce((s, e) => s + e.sequence[h][1], 0) / ELITES;
      currentMean[h] = [hMeanX, hMeanY];

      const hStdX = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][0] - hMeanX, 2), 0) / ELITES) + 0.05;
      const hStdY = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][1] - hMeanY, 2), 0) / ELITES) + 0.05;
      currentStd[h] = [hStdX, hStdY];
    }
  }

  previousOptimalSequence = currentMean;
  return { 
    action: currentMean[0], 
    ensembleUncertainty: totalUncertaintyAtStep0 
  };
};

import { StateVector, ControlInput, PhysicalParams } from "../types";
import { stepDynamicsRK4 } from "./physicsLogic";

const LEARNING_RATE_INITIAL = 0.008;
const MASS_BOUNDS = [0.1, 5.0];
const FRICTION_BOUNDS = [0.0, 1.0];

let currentLR = LEARNING_RATE_INITIAL;
let consecutiveErrorCount = 0;
let lastError = Infinity;

/**
 * Online parameter estimation with projection to admissible physical sets.
 */
export const updateSystemID = (
  prevX: StateVector,
  action: ControlInput,
  currX: StateVector,
  params: PhysicalParams
): PhysicalParams => {
  // Use RK4 prediction for gradient base
  const xPred = stepDynamicsRK4(prevX, action, params);

  const error = Math.sqrt(currX.reduce((s, v, i) => s + Math.pow(v - xPred[i], 2), 0));

  // Adaptive Learning Rate
  if (error > lastError) {
    consecutiveErrorCount++;
    if (consecutiveErrorCount > 3) currentLR *= 0.5;
  } else {
    consecutiveErrorCount = 0;
    currentLR = Math.min(LEARNING_RATE_INITIAL, currentLR * 1.05);
  }
  lastError = error;

  const eps = 1e-3;

  // Numerical Partial Derivatives for Mass
  const xMassPlus = stepDynamicsRK4(prevX, action, { ...params, mass: params.mass + eps });
  const errMassPlus = Math.sqrt(currX.reduce((s, v, i) => s + Math.pow(v - xMassPlus[i], 2), 0));
  const gradMass = (errMassPlus - error) / eps;

  // Numerical Partial Derivatives for Friction
  const xFricPlus = stepDynamicsRK4(prevX, action, { ...params, friction: params.friction + eps });
  const errFricPlus = Math.sqrt(currX.reduce((s, v, i) => s + Math.pow(v - xFricPlus[i], 2), 0));
  const gradFric = (errFricPlus - error) / eps;

  // Update & Project
  const newMass = Math.max(MASS_BOUNDS[0], Math.min(MASS_BOUNDS[1], params.mass - currentLR * gradMass));
  const newFriction = Math.max(FRICTION_BOUNDS[0], Math.min(FRICTION_BOUNDS[1], params.friction - currentLR * gradFric));

  return {
    ...params,
    mass: newMass,
    friction: newFriction
  };
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import SimulationCanvas from './components/SimulationCanvas';
import Dashboard from './components/Dashboard';
import { SimMode, SimState, TelemetryPoint, StateVector, ControlInput, MetaAnalysisResponse } from './types';
import { computeMPCAction } from './services/optimizer';
import { updateSystemID } from './services/systemID';
import { ensembleDynamics } from './services/learnedDynamics';
import { performMetaAnalysis } from './services/geminiService';
import { stepDynamicsRK4 } from './services/physicsLogic';

const App: React.FC = () => {
  const [mode, setMode] = useState<SimMode>(SimMode.MPC_STABILIZATION);
  const [simState, setSimState] = useState<SimState | null>(null);
  const [telemetry, setTelemetry] = useState<TelemetryPoint[]>([]);
  const [metaAnalysis, setMetaAnalysis] = useState<MetaAnalysisResponse | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Physics & Control State
  const [target, setTarget] = useState<[number, number]>([400, 300]);
  const [controlAction, setControlAction] = useState<ControlInput>([0, 0]);
  const [physicsPriors, setPhysicsPriors] = useState({ mass: 1.0, friction: 0.1, gravity: 0.5 });
  const [costWeights, setCostWeights] = useState({ q: 1.5, r: 0.05 });
  const [uncertainty, setUncertainty] = useState(0);

  const historyRef = useRef<SimState[]>([]);
  const lastStateRef = useRef<StateVector | null>(null);
  const benchmarkRef = useRef<{ active: boolean, startTime: number }>({ active: false, startTime: 0 });

  // Main Numerical Control Loop (100Hz)
  const handleStateUpdate = useCallback((state: SimState) => {
    if (lastStateRef.current) {
      // 1. Train Ensemble Residual Model (Physics Ground Truth vs Actual)
      const xPhys = stepDynamicsRK4(lastStateRef.current, controlAction, physicsPriors);
      ensembleDynamics.train(lastStateRef.current, controlAction, state.current, xPhys);

      // 2. Perform Online System Identification
      const updatedParams = updateSystemID(
        lastStateRef.current,
        controlAction,
        state.current,
        physicsPriors
      );
      setPhysicsPriors(updatedParams);
    }

    // 3. Compute MPC action with Uncertainty Awareness
    const { action, ensembleUncertainty } = computeMPCAction(state.current, target, physicsPriors, costWeights);
    setControlAction(action);
    setUncertainty(ensembleUncertainty);

    // 4. Update state tracking
    const predError = lastStateRef.current ? Math.sqrt(state.current.reduce((s, v, i) => s + Math.pow(v - stepDynamicsRK4(lastStateRef.current!, controlAction, physicsPriors)[i], 2), 0)) : 0;

    lastStateRef.current = state.current;
    const enrichedState = { 
      ...state, 
      predictionError: predError, 
      uncertainty: ensembleUncertainty,
      isBenchmarking: benchmarkRef.current.active
    };

    setSimState(enrichedState);
    historyRef.current = [...historyRef.current.slice(-100), enrichedState];

    setTelemetry(prev => [...prev.slice(-60), {
      time: state.time,
      value: predError,
      label: 'L2 Residual'
    }]);
  }, [target, physicsPriors, controlAction, costWeights]);

  // Environmental Shift Benchmark
  const triggerFrictionShift = () => {
    benchmarkRef.current = { active: true, startTime: Date.now() };
    setPhysicsPriors(prev => ({ ...prev, friction: prev.friction > 0.5 ? 0.05 : 0.8 }));
    setTimeout(() => { benchmarkRef.current.active = false; }, 10000);
  };

  useEffect(() => {
    const interval = setInterval(async () => {
      if (!simState || isAnalyzing) return;
      setIsAnalyzing(true);
      try {
        const result = await performMetaAnalysis(simState, historyRef.current);
        setMetaAnalysis(result);
        if (result.suggestedCostTweaks) {
          setCostWeights({
            q: result.suggestedCostTweaks.q_weight,
            r: result.suggestedCostTweaks.r_weight
          });
        }
      } catch (err) { console.error(err); } 
      finally { setIsAnalyzing(false); }
    }, 10000);
    return () => clearInterval(interval);
  }, [simState, isAnalyzing]);

  return (
    <div className="flex h-screen w-screen bg-black text-slate-400 overflow-hidden font-mono selection:bg-blue-900/50">
      <aside className="w-80 bg-slate-950 border-r border-white/5 flex flex-col p-6 shadow-2xl z-20">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-white font-black text-xl italic tracking-tighter">
            <div className="w-8 h-8 bg-indigo-700 rounded-sm flex items-center justify-center not-italic text-sm">Φ</div>
            PHYSICORE <span className="text-indigo-500 font-light">HYBRID</span>
          </div>
          <p className="text-[9px] text-slate-600 mt-2 uppercase tracking-widest">Ensemble Predictive Control</p>
        </header>

        <div className="flex-1 space-y-6 overflow-y-auto pr-2 custom-scroll">
          <section className="bg-slate-900/40 p-4 rounded border border-white/5 space-y-4">
             <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Robust System ID</h3>
             <div className="space-y-3">
               <div>
                 <div className="flex justify-between text-[9px]"><span>Mass Estimate</span><span className="text-white">{physicsPriors.mass.toFixed(4)}kg</span></div>
                 <div className="w-full bg-slate-800 h-1 mt-1"><div className="bg-indigo-500 h-full transition-all duration-300" style={{ width: `${(physicsPriors.mass / 5) * 100}%` }}></div></div>
               </div>
               <div>
                 <div className="flex justify-between text-[9px]"><span>Friction (μ)</span><span className="text-white">{physicsPriors.friction.toFixed(4)}</span></div>
                 <div className="w-full bg-slate-800 h-1 mt-1"><div className="bg-indigo-500 h-full transition-all duration-300" style={{ width: `${physicsPriors.friction * 100}%` }}></div></div>
               </div>
             </div>
          </section>

          <section className="bg-indigo-900/10 border border-indigo-500/20 p-4 rounded">
             <h3 className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-3">Epistemic Uncertainty</h3>
             <div className="flex items-end gap-1 h-12">
               {telemetry.slice(-20).map((t, i) => (
                 <div key={i} className="flex-1 bg-indigo-600/30" style={{ height: `${Math.min(100, (uncertainty * 1000) * (i/20))}%` }}></div>
               ))}
             </div>
             <p className="text-[9px] text-indigo-300 mt-2">Ensemble Variance: <span className="font-bold">{uncertainty.toExponential(3)}</span></p>
          </section>

          <section>
             <h3 className="text-[10px] font-bold text-slate-700 uppercase tracking-widest mb-4">Neural Residuals</h3>
             <div className="grid grid-cols-2 gap-2 text-[10px]">
               <div className="p-3 bg-slate-900/50 border border-white/5">
                 <span className="text-slate-600 block mb-1">State Gain (Q)</span>
                 <span className="text-white">{costWeights.q.toFixed(2)}</span>
               </div>
               <div className="p-3 bg-slate-900/50 border border-white/5">
                 <span className="text-slate-600 block mb-1">Actuation (R)</span>
                 <span className="text-white">{costWeights.r.toFixed(2)}</span>
               </div>
