import { StateVector, ControlInput, PhysicalParams } from "../types";
import { stepDynamicsRK4 } from "./physicsLogic";
import { ensembleDynamics } from "./learnedDynamics";

const HORIZON = 15;
const SAMPLES = 30;
const ELITES = 6;
const ITERATIONS = 2;
const UNCERTAINTY_LAMBDA = 5.0; // Penalty for epistemic uncertainty

// State for Warm-Starting
let previousOptimalSequence: ControlInput[] = Array(HORIZON).fill([0, 0]);

export const computeMPCAction = (
  x0: StateVector,
  target: [number, number],
  p: PhysicalParams,
  weights: { q: number; r: number } = { q: 1.0, r: 0.1 }
): { action: ControlInput, ensembleUncertainty: number } => {

  // 1. Warm-Start: Shift previous sequence left
  // Fix: Explicitly type currentMean and currentStd as ControlInput[] to avoid inference as number[][]
  let currentMean: ControlInput[] = [...previousOptimalSequence.slice(1), [0, 0]];
  let currentStd: ControlInput[] = Array(HORIZON).fill([0.2, 0.2]);

  let totalUncertaintyAtStep0 = 0;

  for (let iter = 0; iter < ITERATIONS; iter++) {
    const trajectories: { cost: number; sequence: ControlInput[] }[] = [];

    for (let s = 0; s < SAMPLES; s++) {
      const sequence: ControlInput[] = [];
      let cost = 0;
      let xt = [...x0] as StateVector;

      for (let h = 0; h < HORIZON; h++) {
        // Sample action for this step
        const a: ControlInput = [
          currentMean[h][0] + (Math.random() - 0.5) * 2 * currentStd[h][0],
          currentMean[h][1] + (Math.random() - 0.5) * 2 * currentStd[h][1]
        ];
        sequence.push(a);

        // Dynamics Step (Hybrid: RK4 Physics + Neural Residual)
        const xPhys = stepDynamicsRK4(xt, a, p);
        const { mean: xRes, variance } = ensembleDynamics.predict(xt, a);

        xt = xPhys.map((v, i) => v + xRes[i]) as StateVector;

        // Cost Calculation
        const distSq = Math.pow(xt[0] - target[0], 2) + Math.pow(xt[1] - target[1], 2);
        const effort = Math.pow(a[0], 2) + Math.pow(a[1], 2);

        // Add Uncertainty Penalty to Cost
        cost += (distSq * weights.q) + (effort * weights.r) + (variance * UNCERTAINTY_LAMBDA);

        if (h === 0 && s === 0) totalUncertaintyAtStep0 = variance;
      }
      trajectories.push({ cost, sequence });
    }

    trajectories.sort((a, b) => a.cost - b.cost);
    const elites = trajectories.slice(0, ELITES);

    // Update Sampling Distribution
    for (let h = 0; h < HORIZON; h++) {
      const hMeanX = elites.reduce((s, e) => s + e.sequence[h][0], 0) / ELITES;
      const hMeanY = elites.reduce((s, e) => s + e.sequence[h][1], 0) / ELITES;
      currentMean[h] = [hMeanX, hMeanY];

      const hStdX = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][0] - hMeanX, 2), 0) / ELITES) + 0.05;
      const hStdY = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][1] - hMeanY, 2), 0) / ELITES) + 0.05;
      currentStd[h] = [hStdX, hStdY];
    }
  }

  previousOptimalSequence = currentMean;
  return { 
    action: currentMean[0], 
    ensembleUncertainty: totalUncertaintyAtStep0 
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { SimState, MetaAnalysisResponse } from "../types";

export const performMetaAnalysis = async (
  state: SimState,
  history: SimState[]
): Promise<MetaAnalysisResponse> => {
  // Fix: Initialize GoogleGenAI strictly with process.env.API_KEY as a named parameter
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    System: You are the "PhysiCore Meta-Analyst".
    Role: Interpret telemetry and diagnostics from a model-based predictive control (MPC) system.

    Diagnostics:
    - Target: [${state.target[0]}, ${state.target[1]}]
    - Estimated Mass: ${state.estimatedParams.mass.toFixed(3)}
    - Estimated Friction: ${state.estimatedParams.friction.toFixed(3)}
    - Prediction L2 Loss: ${state.predictionError.toFixed(5)}
    - Control Effort: ${state.controlEffort.toFixed(3)}
    - Mode: ${state.stability > 80 ? 'Stable Convergence' : 'Oscillatory/Unstable'}

    Analyze the trajectory history and parameter drift. Identify if the model is over-damped or if the system ID is diverging.

    Return strict JSON with specific suggested Q/R weights for the MPC cost function.
  `;

  // Fix: Ensure correct model name and response structure
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          insight: { type: Type.STRING },
          diagnostics: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          suggestedCostTweaks: {
            type: Type.OBJECT,
            properties: {
              q_weight: { type: Type.NUMBER },
              r_weight: { type: Type.NUMBER }
            }
          }
        },
        required: ["insight", "diagnostics", "suggestedCostTweaks"]
      }
    }
  });

  try {
    // Fix: Access response.text directly (property, not a method)
    const text = response.text;
    if (!text) throw new Error("Empty response from meta-analyst");
    return JSON.parse(text.trim()) as MetaAnalysisResponse;
  } catch (e) {
    console.error("Meta-analyst uplink failed", e);
    throw new Error("Invalid analysis response format");
  }
};

import { StateVector, ControlInput, PhysicalParams } from "../types";
import { stepDynamicsRK4 } from "./physicsLogic";
import { ensembleDynamics } from "./learnedDynamics";

const HORIZON = 12; // Slightly shorter horizon for performance
const SAMPLES = 12; // Reduced samples to prevent frame drops
const ELITES = 4;
const ITERATIONS = 1; // Single iteration for real-time responsiveness
const UNCERTAINTY_LAMBDA = 3.0; 

let previousOptimalSequence: ControlInput[] = Array(HORIZON).fill([0, 0] as ControlInput);

export const computeMPCAction = (
  x0: StateVector,
  target: [number, number],
  p: PhysicalParams,
  weights: { q: number; r: number } = { q: 1.0, r: 0.1 }
): { action: ControlInput, ensembleUncertainty: number } => {

  let currentMean: ControlInput[] = [...previousOptimalSequence.slice(1), [0, 0] as ControlInput];
  let currentStd: ControlInput[] = Array(HORIZON).fill([0.15, 0.15] as ControlInput);

  let totalUncertaintyAtStep0 = 0;

  for (let iter = 0; iter < ITERATIONS; iter++) {
    const trajectories: { cost: number; sequence: ControlInput[] }[] = [];

    for (let s = 0; s < SAMPLES; s++) {
      const sequence: ControlInput[] = [];
      let cost = 0;
      let xt = [...x0] as StateVector;

      for (let h = 0; h < HORIZON; h++) {
        const a: ControlInput = [
          currentMean[h][0] + (Math.random() - 0.5) * 2 * currentStd[h][0],
          currentMean[h][1] + (Math.random() - 0.5) * 2 * currentStd[h][1]
        ];
        sequence.push(a);

        const xPhys = stepDynamicsRK4(xt, a, p);
        const { mean: xRes, variance } = ensembleDynamics.predict(xt, a);

        xt = xPhys.map((v, i) => v + xRes[i]) as StateVector;

        const distSq = Math.pow(xt[0] - target[0], 2) + Math.pow(xt[1] - target[1], 2);
        const effort = Math.pow(a[0], 2) + Math.pow(a[1], 2);

        cost += (distSq * weights.q) + (effort * weights.r) + (variance * UNCERTAINTY_LAMBDA);

        if (h === 0 && s === 0) totalUncertaintyAtStep0 = variance;
      }
      trajectories.push({ cost, sequence });
    }

    trajectories.sort((a, b) => a.cost - b.cost);
    const elites = trajectories.slice(0, ELITES);

    for (let h = 0; h < HORIZON; h++) {
      const hMeanX = elites.reduce((s, e) => s + e.sequence[h][0], 0) / ELITES;
      const hMeanY = elites.reduce((s, e) => s + e.sequence[h][1], 0) / ELITES;
      currentMean[h] = [hMeanX, hMeanY];

      const hStdX = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][0] - hMeanX, 2), 0) / ELITES) + 0.05;
      const hStdY = Math.sqrt(elites.reduce((s, e) => s + Math.pow(e.sequence[h][1] - hMeanY, 2), 0) / ELITES) + 0.05;
      currentStd[h] = [hStdX, hStdY];
    }
  }

  previousOptimalSequence = currentMean;
  return { 
    action: currentMean[0], 
    ensembleUncertainty: totalUncertaintyAtStep0 
  };
};

import React, { useEffect, useRef } from 'react';
import { SimMode, SimState, StateVector, ControlInput } from '../types';
import { stepDynamicsRK4 } from '../services/physicsLogic';

declare const Matter: any;

interface SimulationCanvasProps {
  mode: SimMode;
  onStateUpdate: (state: SimState) => void;
  target: [number, number];
  controlAction: ControlInput;
  physicsPriors: { mass: number; friction: number; gravity: number };
}

const SimulationCanvas: React.FC<SimulationCanvasProps> = ({ mode, onStateUpdate, target, controlAction, physicsPriors }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<any>(null);
  const robotRef = useRef<any>(null);

  useEffect(() => {
    if (!containerRef.current || !canvasRef.current || typeof Matter === 'undefined') return;

    const engine = Matter.Engine.create();
    engineRef.current = engine;
    engine.world.gravity.y = 0; 

    const { width, height } = containerRef.current.getBoundingClientRect();
    const actualWidth = width || 800;
    const actualHeight = height || 600;

    const render = Matter.Render.create({
      element: containerRef.current,
      canvas: canvasRef.current,
      engine: engine,
      options: {
        width: actualWidth,
        height: actualHeight,
        wireframes: false,
        background: 'transparent',
      }
    });

    const robot = Matter.Bodies.rectangle(actualWidth / 2, actualHeight / 2, 60, 30, {
      friction: 0,
      airFriction: 0,
      restitution: 0.1,
      render: { fillStyle: '#4f46e5', strokeStyle: '#818cf8', lineWidth: 2 }
    });
    robotRef.current = robot;

    const ground = Matter.Bodies.rectangle(actualWidth / 2, actualHeight + 25, actualWidth, 50, { isStatic: true, render: { fillStyle: '#0f172a' } });
    Matter.Composite.add(engine.world, [robot, ground]);

    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);
    Matter.Render.run(render);

    // Throttled control loop (approx 30Hz) to allow UI breathing room
    const controlLoop = setInterval(() => {
      const b = robotRef.current;
      if (!b) return;

      Matter.Body.applyForce(b, b.position, { 
        x: controlAction[0] * 0.001, 
        y: (controlAction[1] + physicsPriors.gravity * 10) * 0.001 
      });

      onStateUpdate({
        current: [b.position.x, b.position.y, b.velocity.x, b.velocity.y, b.angle, b.angularVelocity],
        target: target,
        estimatedParams: physicsPriors,
        predictionError: 0, 
        controlEffort: Math.abs(controlAction[0]) + Math.abs(controlAction[1]),
        stability: 100 - Math.min(100, (Math.abs(b.angularVelocity) * 100)),
        time: Date.now(),
        controlAction: controlAction,
        uncertainty: 0,
        isBenchmarking: false
      });
    }, 32);

    const drawOverlay = () => {
      const ctx = canvasRef.current?.getContext('2d');
      if (!ctx || !robotRef.current) return;

      let tempX: StateVector = [
        robotRef.current.position.x,
        robotRef.current.position.y,
        robotRef.current.velocity.x,
        robotRef.current.velocity.y,
        robotRef.current.angle,
        robotRef.current.angularVelocity
      ];

      ctx.beginPath();
      ctx.setLineDash([2, 4]);
      ctx.strokeStyle = 'rgba(99, 102, 241, 0.4)';
      ctx.moveTo(tempX[0], tempX[1]);

      for (let i = 0; i < 15; i++) {
        tempX = stepDynamicsRK4(tempX, controlAction, physicsPriors);
        ctx.lineTo(tempX[0], tempX[1]);
      }
      ctx.stroke();
      ctx.setLineDash([]);

      ctx.beginPath();
      ctx.arc(target[0], target[1], 8, 0, Math.PI * 2);
      ctx.strokeStyle = '#f43f5e';
      ctx.lineWidth = 2;
      ctx.stroke();

      requestAnimationFrame(drawOverlay);
    };
    const overlayReq = requestAnimationFrame(drawOverlay);

    return () => {
      clearInterval(controlLoop);
      cancelAnimationFrame(overlayReq);
      Matter.Engine.clear(engine);
      Matter.Render.stop(render);
    };
  }, [mode]);

  return (
    <div ref={containerRef} className="w-full h-full relative overflow-hidden bg-slate-950 border border-slate-900 rounded-sm">
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

export default SimulationCanvas;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import SimulationCanvas from './components/SimulationCanvas';
import Dashboard from './components/Dashboard';
import { SimMode, SimState, TelemetryPoint, StateVector, ControlInput, MetaAnalysisResponse } from './types';
import { computeMPCAction } from './services/optimizer';
import { updateSystemID } from './services/systemID';
import { ensembleDynamics } from './services/learnedDynamics';
import { performMetaAnalysis } from './services/geminiService';
import { stepDynamicsRK4 } from './services/physicsLogic';

const App: React.FC = () => {
  const [mode, setMode] = useState<SimMode>(SimMode.MPC_STABILIZATION);
  const [simState, setSimState] = useState<SimState | null>(null);
  const [telemetry, setTelemetry] = useState<TelemetryPoint[]>([]);
  const [metaAnalysis, setMetaAnalysis] = useState<MetaAnalysisResponse | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [target, setTarget] = useState<[number, number]>([400, 300]);
  const [controlAction, setControlAction] = useState<ControlInput>([0, 0]);
  const [physicsPriors, setPhysicsPriors] = useState({ mass: 1.0, friction: 0.1, gravity: 0.5 });
  const [costWeights, setCostWeights] = useState({ q: 1.5, r: 0.05 });
  const [uncertainty, setUncertainty] = useState(0);

  const historyRef = useRef<SimState[]>([]);
  const lastStateRef = useRef<StateVector | null>(null);
  const benchmarkRef = useRef<{ active: boolean, startTime: number }>({ active: false, startTime: 0 });

  const handleStateUpdate = useCallback((state: SimState) => {
    if (lastStateRef.current) {
      const xPhys = stepDynamicsRK4(lastStateRef.current, controlAction, physicsPriors);
      ensembleDynamics.train(lastStateRef.current, controlAction, state.current, xPhys);

      const updatedParams = updateSystemID(
        lastStateRef.current,
        controlAction,
        state.current,
        physicsPriors
      );
      setPhysicsPriors(updatedParams);
    }

    const { action, ensembleUncertainty } = computeMPCAction(state.current, target, physicsPriors, costWeights);
    setControlAction(action);
    setUncertainty(ensembleUncertainty);

    const predError = lastStateRef.current ? Math.sqrt(state.current.reduce((s, v, i) => s + Math.pow(v - stepDynamicsRK4(lastStateRef.current!, controlAction, physicsPriors)[i], 2), 0)) : 0;

    lastStateRef.current = state.current;
    const enrichedState = { 
      ...state, 
      predictionError: predError, 
      uncertainty: ensembleUncertainty,
      isBenchmarking: benchmarkRef.current.active
    };

    setSimState(enrichedState);
    historyRef.current = [...historyRef.current.slice(-60), enrichedState];

    setTelemetry(prev => [...prev.slice(-40), {
      time: state.time,
      value: predError,
      label: 'L2 Residual'
    }]);
  }, [target, physicsPriors, controlAction, costWeights]);

  const triggerFrictionShift = () => {
    benchmarkRef.current = { active: true, startTime: Date.now() };
    setPhysicsPriors(prev => ({ ...prev, friction: prev.friction > 0.4 ? 0.05 : 0.7 }));
    setTimeout(() => { benchmarkRef.current.active = false; }, 8000);
  };

  // Fixed MetaAnalysis Effect: Use an interval that doesn't clear on every simState update
  useEffect(() => {
    const triggerAnalysis = async () => {
      // Use the latest history value from the ref to avoid dependency on simState
      if (historyRef.current.length < 10 || isAnalyzing) return;

      setIsAnalyzing(true);
      try {
        const latestState = historyRef.current[historyRef.current.length - 1];
        const result = await performMetaAnalysis(latestState, historyRef.current);
        setMetaAnalysis(result);
        if (result.suggestedCostTweaks) {
          setCostWeights({
            q: result.suggestedCostTweaks.q_weight,
            r: result.suggestedCostTweaks.r_weight
          });
        }
      } catch (err) {
        console.error("Meta-analyst failed:", err);
      } finally {
        setIsAnalyzing(false);
      }
    };

    const interval = setInterval(triggerAnalysis, 15000);
    return () => clearInterval(interval);
  }, []); // Only run once on mount

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-400 overflow-hidden font-mono">
      <aside className="w-80 bg-slate-900/50 border-r border-white/5 flex flex-col p-6 shadow-2xl z-20">
        <header className="mb-8">
          <div className="flex items-center gap-2 text-white font-black text-xl italic tracking-tighter">
            <div className="w-8 h-8 bg-indigo-700 rounded-sm flex items-center justify-center not-italic text-sm shadow-[0_0_15px_rgba(79,70,229,0.4)]">Φ</div>
            PHYSICORE <span className="text-indigo-400 font-light">HYBRID</span>
          </div>
          <p className="text-[9px] text-slate-600 mt-2 uppercase tracking-widest">Ensemble Predictive Control</p>
        </header>

        <div className="flex-1 space-y-6 overflow-y-auto pr-2 custom-scroll">
          <section className="bg-slate-900/80 p-4 rounded border border-white/5 space-y-4 shadow-inner">
             <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Robust System ID</h3>
             <div className="space-y-3">
               <div>
                 <div className="flex justify-between text-[9px] mb-1"><span>Mass Estimate</span><span className="text-white">{physicsPriors.mass.toFixed(4)}kg</span></div>
                 <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden"><div className="bg-indigo-500 h-full transition-all duration-300" style={{ width: `${(physicsPriors.mass / 5) * 100}%` }}></div></div>
               </div>
               <div>
                 <div className="flex justify-between text-[9px] mb-1"><span>Friction (μ)</span><span className="text-white">{physicsPriors.friction.toFixed(4)}</span></div>
                 <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden"><div className="bg-indigo-500 h-full transition-all duration-300" style={{ width: `${physicsPriors.friction * 100}%` }}></div></div>
               </div>
             </div>
          </section>

          <section className="bg-indigo-950/20 border border-indigo-500/20 p-4 rounded shadow-sm">
             <h3 className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-3">Epistemic Uncertainty</h3>
             <div className="flex items-end gap-1 h-12 bg-black/20 rounded p-1">
               {telemetry.slice(-24).map((t, i) => (
                 <div key={i} className="flex-1 bg-indigo-600/40 rounded-t-sm" style={{ height: `${Math.min(100, (uncertainty * 500) + (i * 2))}%` }}></div>
               ))}
             </div>
             <p className="text-[9px] text-indigo-300/70 mt-2 flex justify-between">
               <span>Variance Threshold</span>
               <span className="font-bold text-indigo-400">{uncertainty.toExponential(2)}</span>
             </p>
          </section>

          <section>
             <h3 className="text-[10px] font-bold text-slate-700 uppercase tracking-widest mb-4 px-1">Neural Residuals</h3>
             <div className="grid grid-cols-2 gap-2 text-[10px]">
               <div className="p-3 bg-slate-900/50 border border-white/5 rounded">
                 <span className="text-slate-600 block mb-1">State Gain (Q)</span>
                 <span className="text-white font-bold">{costWeights.q.toFixed(2)}</span>
               </div>
               <div className="p-3 bg-slate-900/50 border border-white/5 rounded">
                 <span className="text-slate-600 block mb-1">Actuation (R)</span>
                 <span className="text-white font-bold">{costWeights.r.toFixed(2)}</span>
               </div>
             </div>
          </section>
        </div>

        <footer className="mt-8 pt-6 border-t border-white/5 space-y-3">
