import { FailureLog } from "../types";

const DB_NAME = 'PhysiCore_RIL_DB';
const STORE_NAME = 'failures';

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, 1);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const logFailure = async (log: FailureLog) => {
  const db = await initDB();
  return new Promise<void>((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, 'readwrite');
    tx.objectStore(STORE_NAME).put(log);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
};

export const getFailures = async (): Promise<FailureLog[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, 'readonly');
    const request = tx.objectStore(STORE_NAME).getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

import { StateVector, PhysicalParams } from "../types";

export interface ResidualReport {
  pattern: string;
  forceError: number;
  confidence: number;
}

export const calculateResiduals = (predicted: StateVector, actual: StateVector) => {
  return {
    posError: Math.sqrt(Math.pow(actual[0] - predicted[0], 2) + Math.pow(actual[1] - predicted[1], 2)),
    velError: Math.sqrt(Math.pow(actual[2] - predicted[2], 2) + Math.pow(actual[3] - predicted[3], 2))
  };
};

export const classifyPattern = (history: number[]): string => {
  if (history.length < 5) return "nominal";
  const recent = history.slice(-10);
  const mean = recent.reduce((a, b) => a + b, 0) / recent.length;

  if (mean > 2.0) return "systematic_overprediction";
  if (mean < -2.0) return "systematic_underprediction";

  // Simplified oscillation check
  let signChanges = 0;
  for (let i = 1; i < recent.length; i++) {
    if ((recent[i] >= 0 && recent[i-1] < 0) || (recent[i] < 0 && recent[i-1] >= 0)) {
      signChanges++;
    }
  }
  if (signChanges > 4) return "oscillation";

  return "nominal";
};

import { GoogleGenAI, Type } from "@google/genai";
import { SimState, MetaAnalysisResponse } from "../types";

const RIL_SYSTEM_PROMPT = `
# CORE IDENTITY
You are the Robotics Intelligence Layer (RIL) - a conversational, learning, and adaptive supervisor that sits above physics simulation and real robot control systems.

# PRIMARY MISSION
Debug and fix sim-to-real failures in contact-rich manipulation tasks by:
1. Identifying physics model mismatches between simulation and reality.
2. Diagnosing why contact predictions fail (force, friction, deformation).
3. Suggesting concrete parameter corrections with mathematical reasoning.

# TECHNICAL CONTEXT
Physics engine: Matter.js + custom RK4. Hybrid: Rigid + Fluid + Textile.
MPC: CEM optimizer. Residuals: Ensemble Neural Networks.

# TASK
Analyze the provided telemetry and return a structured diagnostic report. If prediction errors are high, suggest specific parameter updates for mass, friction, textile_k, or damping.
`;

export const performRILAnalysis = async (
  state: SimState,
  history: SimState[],
  userQuery?: string
): Promise<MetaAnalysisResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const telemetryContext = `
    CURRENT STATE:
    - Target: [${state.target}]
    - Prediction L2 Loss: ${state.predictionError.toFixed(5)}
    - Stability: ${state.stability}%
    - Params: Mass=${state.estimatedParams.mass}, Friction=${state.estimatedParams.friction}, TextileK=${state.estimatedParams.textile_k}

    ${userQuery ? `USER QUERY: ${userQuery}` : "AUTONOMOUS DIAGNOSIS"}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: telemetryContext,
      config: {
        systemInstruction: RIL_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            insight: { type: Type.STRING },
            diagnostics: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            suggestedCostTweaks: {
              type: Type.OBJECT,
              properties: {
                q_weight: { type: Type.NUMBER },
                r_weight: { type: Type.NUMBER }
              },
              required: ["q_weight", "r_weight"]
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  parameter: { type: Type.STRING },
                  value: { type: Type.NUMBER },
                  rationale: { type: Type.STRING }
                },
                required: ["parameter", "value", "rationale"]
              }
            }
          },
          required: ["insight", "diagnostics", "suggestedCostTweaks"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from RIL");
    return JSON.parse(text.trim()) as MetaAnalysisResponse;
  } catch (e: any) {
    console.error("RIL Intelligence layer failed", e);
    throw e;
  }
};

