             🔥 Shift Environment
           </button>
        </footer>
      </aside>

      <main className="flex-1 flex flex-col p-8 relative bg-black/20 backdrop-blur-3xl min-w-0">
        <div className="flex-1 relative mb-8 group rounded shadow-2xl overflow-hidden border border-white/5 bg-slate-950">
