            onReset={() => {
              setPhysicsPriors({ mass: 1, friction: 0.1, gravity: 0.5, textile_k: 400, damping: 0.15 });
              historyRef.current = [];
              setTelemetry([]);
              setMessages([]);
            }}
          />

          <section className="bg-indigo-950/20 border border-indigo-500/20 p-4 rounded">
             <h3 className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-3">Model Convergence</h3>
             <div className="flex items-end gap-1 h-12 bg-black/20 rounded p-1">
