const App: React.FC = () => {
  const [hasEntered, setHasEntered] = useState(false);
  const [isMatterLoaded, setIsMatterLoaded] = useState(false);
  const [simState, setSimState] = useState<SimState | null>(null);
  const [telemetry, setTelemetry] = useState<TelemetryPoint[]>([]);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [quotaExceeded, setQuotaExceeded] = useState(false);
  const [isDeploying, setIsDeploying] = useState(false);

  const [target, setTarget] = useState<[number, number]>([400, 300]);
  const [controlAction, setControlAction] = useState<ControlInput>([0, 0]);
  const [physicsPriors, setPhysicsPriors] = useState<PhysicalParams>({ mass: 1.0, friction: 0.1, gravity: 0.5, textile_k: 400, damping: 0.15 });
  const [costWeights, setCostWeights] = useState({ q: 1.5, r: 0.05 });
  const [uncertainty, setUncertainty] = useState(0);

  const historyRef = useRef<SimState[]>([]);
  const lastStateRef = useRef<StateVector | null>(null);

  useEffect(() => {
    const checkMatter = () => {
      if ((window as any).Matter) setIsMatterLoaded(true);
      else setTimeout(checkMatter, 100);
    };
    checkMatter();
  }, []);

  const handleStateUpdate = useCallback((state: SimState) => {
    if (lastStateRef.current) {
      const xPhys = stepDynamicsRK4(lastStateRef.current, controlAction, physicsPriors);
      ensembleDynamics.train(lastStateRef.current, controlAction, state.current, xPhys);

      const updatedParams = updateSystemID(lastStateRef.current, controlAction, state.current, physicsPriors);
      setPhysicsPriors(prev => ({ ...prev, mass: updatedParams.mass, friction: updatedParams.friction }));

      const predError = Math.sqrt(state.current.reduce((s, v, i) => s + Math.pow(v - xPhys[i], 2), 0));
      if (predError > 15.0) {
        logFailure({
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          task: "live_operation",
          failure_type: "RESIDUAL_MISMATCH",
          sim_params: { ...physicsPriors }
        });
      }
    }

    const { action, ensembleUncertainty } = computeMPCAction(state.current, target, physicsPriors, costWeights);
    setControlAction(action);
    setUncertainty(ensembleUncertainty);

    const xPhysFinal = lastStateRef.current ? stepDynamicsRK4(lastStateRef.current, controlAction, physicsPriors) : state.current;
    const predError = lastStateRef.current ? Math.sqrt(state.current.reduce((s, v, i) => s + Math.pow(v - xPhysFinal[i], 2), 0)) : 0;

    lastStateRef.current = state.current;
    const enrichedState = { ...state, predictionError: predError, uncertainty: ensembleUncertainty };

    setSimState(enrichedState);
    historyRef.current = [...historyRef.current.slice(-120), enrichedState];
    setTelemetry(prev => [...prev.slice(-60), { time: state.time, value: predError, label: 'L2 Residual' }]);
  }, [target, physicsPriors, controlAction, costWeights]);

  const handleQuery = async (query: string) => {
    if (isAnalyzing || quotaExceeded) return;
    setMessages(prev => [...prev, { role: 'user', content: query, timestamp: Date.now() }]);
    setIsAnalyzing(true);
    try {
      const result = await performRILAnalysis(historyRef.current[historyRef.current.length - 1], historyRef.current, query);
      if (result.suggestedCostTweaks) setCostWeights({ q: result.suggestedCostTweaks.q_weight, r: result.suggestedCostTweaks.r_weight });
      setMessages(prev => [...prev, { role: 'assistant', content: result.insight, timestamp: Date.now() }]);
    } catch (err: any) {
      if (err.message === "QUOTA_EXHAUSTED") setQuotaExceeded(true);
      setMessages(prev => [...prev, { role: 'assistant', content: "Uplink Error. Operating on local physics belief.", timestamp: Date.now() }]);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleDeploy = () => {
    setIsDeploying(true);
    setTimeout(() => {
      setIsDeploying(false);
      const deploymentPackage = {
        metadata: {
          client: "Physicore-v2.4",
          timestamp: new Date().toISOString(),
          target_hardware: "Generic-ARM64-Robot",
        },
        calibrated_parameters: physicsPriors,
        learned_residual_weights: "ENVELOPE_BINARY_V1_7B_PAR_LEARNED",
        control_logic: {
          optimizer: "MPC-CEM",
          horizon: 12,
          cost_matrices: costWeights
        },
        integration_snippet: `
# Physicore Bridge for Python/ROS2
import json
import numpy as np

def apply_correction(state, action):
    # Load calibrated mass: ${physicsPriors.mass.toFixed(4)}
    # Load calibrated friction: ${physicsPriors.friction.toFixed(4)}
    # This snippet connects your robot to the learned residual models.
    pass
        `
      };
      const blob = new Blob([JSON.stringify(deploymentPackage, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `physicore_edge_deploy_${Date.now()}.json`;
      a.click();
    }, 1500);
  };

  if (!hasEntered) return <PhysicoreDiscovery onEnter={() => setHasEntered(true)} />;

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-400 overflow-hidden font-mono selection:bg-indigo-500/40">
      <aside className="w-80 bg-slate-900/60 border-r border-white/5 flex flex-col p-6 shadow-2xl z-20 shrink-0">
        <header className="mb-10">
          <div className="flex items-center gap-3 text-white font-black text-2xl italic tracking-tighter">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center not-italic text-sm shadow-[0_0_20px_rgba(79,70,229,0.3)]">P</div>
            PHYSI<span className="text-indigo-400 font-light italic tracking-tight">CORE</span>
          </div>
          <p className="text-[9px] text-slate-600 mt-2 uppercase tracking-[0.4em] font-bold">Reality Bridging Unit</p>
        </header>

        <div className="flex-1 space-y-6 overflow-y-auto pr-2 custom-scroll">
          <ParameterEditor 
            params={physicsPriors} 
            onChange={(u) => setPhysicsPriors(p => ({ ...p, ...u }))}
            onReset={() => {
              setPhysicsPriors({ mass: 1, friction: 0.1, gravity: 0.5, textile_k: 400, damping: 0.15 });
              historyRef.current = [];
              setTelemetry([]);
              setMessages([]);
            }}
          />

          <section className="bg-indigo-950/20 border border-indigo-500/20 p-4 rounded shadow-inner">
             <h3 className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-3">Epistemic Drift</h3>
             <div className="flex items-end gap-0.5 h-16 bg-black/40 rounded p-1 overflow-hidden">
               {telemetry.slice(-32).map((t, i) => (
                 <div key={i} className="flex-1 bg-indigo-500/60 rounded-t-[1px]" style={{ height: `${Math.min(100, (t.value * 200) + (i * 1.5))}%` }}></div>
               ))}
             </div>
             <p className="text-[9px] text-indigo-300/50 mt-2 flex justify-between">
               <span>Simulation Variance</span>
               <span className="font-bold text-indigo-400">{(uncertainty * 100).toFixed(2)}%</span>
             </p>
          </section>
        </div>

        <footer className="mt-8 pt-6 border-t border-white/5 space-y-3">
           <button 
             onClick={handleDeploy}
             disabled={isDeploying}
             className="w-full py-4 bg-indigo-600 text-white hover:bg-indigo-500 text-[11px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-3 rounded shadow-lg disabled:opacity-50 group active:scale-[0.98]"
           >
             {isDeploying ? 'Packaging Binaries...' : 'Deploy to Hardware'}
             {!isDeploying && <svg className="w-4 h-4 group-hover:translate-y-[-2px] transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>}
           </button>
           <p className="text-[8px] text-center text-slate-700 uppercase tracking-tighter">Generates Production-Ready ROS2 Config</p>
        </footer>
      </aside>

      <main className="flex-1 flex flex-col p-8 relative bg-[#020617] min-w-0">
        <div className="flex-1 relative mb-8 rounded-xl shadow-[0_0_80px_rgba(0,0,0,0.5)] overflow-hidden border border-white/5 bg-slate-900/10">
          {isMatterLoaded ? (
            <SimulationCanvas 
              mode={SimMode.MPC_STABILIZATION} 
              onStateUpdate={handleStateUpdate} 
              target={target}
              controlAction={controlAction}
              physicsPriors={physicsPriors}
            />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center text-indigo-500 text-[10px] uppercase tracking-[0.5em] gap-4">
              <div className="w-12 h-12 border-2 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
              Booting High-Fidelity Physics...
            </div>
          )}

          <div className="absolute inset-0 cursor-crosshair z-10"
            onMouseMove={(e) => { if (e.buttons === 1) {
              const rect = e.currentTarget.getBoundingClientRect();
              setTarget([e.clientX - rect.left, e.clientY - rect.top]);
            }}}
            onClick={(e) => {
              const rect = e.currentTarget.getBoundingClientRect();
              setTarget([e.clientX - rect.left, e.clientY - rect.top]);
            }}
          />

          <div className="absolute top-6 left-6 pointer-events-none z-20">
            <div className="bg-slate-950/80 border border-white/10 p-5 rounded backdrop-blur-xl shadow-2xl">
              <div className="text-[11px] text-indigo-400 font-bold mb-2 tracking-widest uppercase flex items-center gap-2">
                <span className="w-2 h-2 bg-indigo-500 rounded-full animate-pulse shadow-[0_0_10px_#6366f1]"></span>
                Live Convergence Data
              </div>
              <div className="text-[10px] text-slate-500 space-y-1.5 font-mono">
                <div className="flex justify-between gap-8"><span>GRADIENT</span> <span className="text-slate-300">RK4_ADAPTIVE</span></div>
                <div className="flex justify-between gap-8"><span>RESIDUAL</span> <span className="text-white">{simState?.predictionError.toFixed(5) || '0.00000'}</span></div>
                <div className="flex justify-between gap-8"><span>HW_LINK</span> <span className="text-emerald-500">OPTIMIZED</span></div>
              </div>
            </div>
          </div>
        </div>

        <div className="h-64 grid grid-cols-12 gap-6 shrink-0 min-h-0">
           <div className="col-span-7 h-full">
             <Dashboard telemetry={telemetry} avgVelocity={simState?.current[2] || 0} stability={simState?.stability || 0} />
           </div>
           <div className="col-span-5 h-full">
             <ChatInterface onQuery={handleQuery} messages={messages} isAnalyzing={isAnalyzing} />
